import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "react-query";
import { payrollAPI } from "../utils/api";
import LoadingSpinner from "../components/common/LoadingSpinner";
import StatsCard from "../components/common/StatsCard";
import { BanknotesIcon, CheckCircleIcon, ClockIcon } from "@heroicons/react/24/outline";
import toast from "react-hot-toast";
import clsx from "clsx";
const STATUS_COLOR = { draft:"badge-neutral", pending_approval:"badge-warning", approved:"badge-info", paid:"badge-success" };
export default function Payroll() {
  const qc = useQueryClient();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth()+1);
  const [year, setYear] = useState(now.getFullYear());
  const { data, isLoading } = useQuery(["payroll",month,year], () => payrollAPI.getAll({month,year,limit:50}).then(r=>r.data));
  const { data: summary } = useQuery(["payrollSummary",month,year], () => payrollAPI.getSummary({month,year}).then(r=>r.data.data));
  const genMut = useMutation(()=>payrollAPI.generate({month,year}), { onSuccess:()=>{toast.success("Payroll generated");qc.invalidateQueries(["payroll"])} });
  const bulkMut = useMutation(()=>payrollAPI.bulkApprove({month,year}), { onSuccess:()=>{toast.success("All approved");qc.invalidateQueries(["payroll"])} });
  const approveMut = useMutation(payrollAPI.approve, { onSuccess:()=>{toast.success("Approved");qc.invalidateQueries(["payroll"])} });
  if (isLoading) return <LoadingSpinner />;
  const records = data?.data || [];
  const fmt = n => n!=null?`₹${Number(n).toLocaleString("en-IN",{maximumFractionDigits:0})}`:"—";
  return (
    <div className="space-y-5 animate-in">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div><h1 className="page-title">Payroll</h1><p className="text-slate-500 text-sm mt-0.5">{records.length} records for {month}/{year}</p></div>
        <div className="flex gap-2 flex-wrap">
          <select className="input w-auto" value={month} onChange={e=>setMonth(+e.target.value)}>{Array.from({length:12},(_,i)=>(<option key={i+1} value={i+1}>{new Date(2024,i).toLocaleString("default",{month:"long"})}</option>))}</select>
          <select className="input w-auto" value={year} onChange={e=>setYear(+e.target.value)}>{[2023,2024,2025,2026].map(y=>(<option key={y} value={y}>{y}</option>))}</select>
          <button onClick={()=>genMut.mutate()} disabled={genMut.isLoading} className="btn-secondary">{genMut.isLoading?"Generating…":"Generate Payroll"}</button>
          <button onClick={()=>bulkMut.mutate()} disabled={bulkMut.isLoading} className="btn-primary"><CheckCircleIcon className="w-4 h-4"/>Bulk Approve</button>
        </div>
      </div>
      {summary&&<div className="grid grid-cols-3 gap-4"><StatsCard title="Total Gross" value={fmt(summary.totalGross)} icon={BanknotesIcon} color="green"/><StatsCard title="Total Deductions" value={fmt(summary.totalDeductions)} icon={ClockIcon} color="orange"/><StatsCard title="Net Payable" value={fmt(summary.totalNet)} icon={CheckCircleIcon} color="indigo"/></div>}
      <div className="card overflow-x-auto"><table className="w-full"><thead className="border-b border-slate-100"><tr>{["Employee","Basic","Gross","Deductions","Net Salary","Status","Actions"].map(h=>(<th key={h} className="table-header">{h}</th>))}</tr></thead><tbody>
        {records.length===0?(<tr><td colSpan={7} className="text-center py-10 text-slate-400 text-sm">No records. Click Generate Payroll to create records for this month.</td></tr>):records.map(p=>(<tr key={p.id} className="table-row">
          <td className="table-cell"><p className="font-medium">{p.employee?.firstName} {p.employee?.lastName}</p><p className="text-xs text-slate-400">{p.employee?.employeeId}</p></td>
          <td className="table-cell">{fmt(p.basicSalary)}</td>
          <td className="table-cell">{fmt(p.grossEarnings)}</td>
          <td className="table-cell text-red-600">-{fmt(p.totalDeductions)}</td>
          <td className="table-cell font-semibold text-slate-900">{fmt(p.netSalary)}</td>
          <td className="table-cell"><span className={clsx("badge",STATUS_COLOR[p.status]||"badge-neutral")}>{p.status?.replace("_"," ")}</span></td>
          <td className="table-cell">{p.status==="draft"&&<button onClick={()=>approveMut.mutate(p.id)} className="text-xs text-primary-600 hover:underline">Approve</button>}</td>
        </tr>))}
      </tbody></table></div>
    </div>
  );
}
